import React from 'react';
import { HeadFC, graphql } from 'gatsby';
import Layout from '../layout';
import { SnippetPageProps } from 'types';
// import Head from 'components/head';
import SnippetList from 'components/snippet-list';
import SEO from 'components/SEO';

interface HeadFrontmatterProps {
  data: {
    allMarkdownRemark: {
      edges: {
        node: {
          frontmatter: {
            title: string;
            summary: string;
            thumbnail: {
              publicURL?: string;
            };
          };
        };
      };
    };
  };
}

export const Head: HeadFC<HeadFrontmatterProps> = ({ location, data }: any) => {
  const { title, summary, thumbnail } = data;

  return (
    <>
      <SEO
        title={title}
        description={summary}
        pathname={location.pathname ?? ''}
        image={thumbnail?.publicURL ?? ''}
      />
    </>
  );
};

const Snippet = function ({
  data: {
    site: {
      siteMetadata: { title, description, siteUrl },
    },
    allMarkdownRemark: { edges },
  },
}: SnippetPageProps) {
  return (
    <Layout title={title} description={description} url={siteUrl}>
      {/* <Head /> */}
      <SnippetList edges={edges} />
    </Layout>
  );
};

export default Snippet;

export const getSnippetList = graphql`
  query getSnippetList {
    site {
      siteMetadata {
        title
        description
        siteUrl
      }
    }
    allMarkdownRemark(
      sort: [{ frontmatter: { date: DESC } }, { frontmatter: { title: ASC } }]
      filter: {
        frontmatter: {
          categories: { regex: "/snippet/", ne: null }
          draft: { eq: false }
        }
      }
    ) {
      edges {
        node {
          id
          html
          frontmatter {
            title
            summary
            date(formatString: "MMMM DD, YYYY")
            categories
            draft
          }
        }
      }
    }
    file(name: { eq: "profile-image" }) {
      childImageSharp {
        gatsbyImageData(width: 120, height: 120)
      }
      publicURL
    }
  }
`;
